  ('pukao-d0d1b9a2-moex-00069', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-fa8ff513', 'sub-pukao-d0d1b9a2-01', NULL, 'single_choice', '審計機關審核甲機關X3年度決算時發現，甲機關於X3年4月為投資1,000萬元取得C公司10% 股權，自經常門業務費流用至資本門一案，因未編列預算，且與預算法流用規定不符，悉數遭減 列並請補正。依中央政府普通公務單位會計制度之一致規定，減列時甲機關應作之分錄為何？', '["借：應收剔除經費1,000萬元，貸：其他長期投資1,000萬元", "借：其他應收款1,000萬元，貸：資產負債淨額1,000萬元", "借：其他應收款1,000萬元，貸：其他長期投資1,000萬元", "借：應收剔除經費1,000萬元，貸：資產負債淨額1,000萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "bd075477360a", "answer_pdf_sha1": "218bb9f9db20", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00070', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-fa8ff513', 'sub-pukao-d0d1b9a2-01', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，下列何者屬會影響公務機關本年度收入支出增減 變動之交易事項？', '["代收款之支付", "存出保證金之支付", "以零用金支付員工差旅費", "配合徵課會計過渡時期之作法，於有強制收取權時認列應收之稅款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "bd075477360a", "answer_pdf_sha1": "218bb9f9db20", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
